import{c as t,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Latent Space — 2026-05-01","description":"","frontmatter":{"title":"Latent Space — 2026-05-01","date":"2026-05-01T00:00:00.000Z","source":"Latent Space","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-01-latent-space.md","filePath":"research/ai-news/2026-05/2026-05-01-latent-space.md","lastUpdated":1779894392000}'),s={name:"research/ai-news/2026-05/2026-05-01-latent-space.md"};function o(i,e,l,p,c,h){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="🔬-latent-space-—-2026-05-01" tabindex="-1">🔬 Latent Space — 2026-05-01 <a class="header-anchor" href="#🔬-latent-space-—-2026-05-01" aria-label="Permalink to &quot;🔬 Latent Space — 2026-05-01&quot;">​</a></h1><blockquote><p>swyx 開發者簡報，未公開專案 + 工程視角 來源：<a href="https://www.latent.space/feed" target="_blank" rel="noreferrer">Latent Space</a></p></blockquote><hr><h2 id="ainews-agents-for-everything-else-codex-for-knowledge-work-claude-for-creative-work" tabindex="-1"><a href="https://www.latent.space/p/ainews-agents-for-everything-else" target="_blank" rel="noreferrer">[AINews] Agents for Everything Else: Codex for Knowledge Work, Claude for Creative Work</a> <a class="header-anchor" href="#ainews-agents-for-everything-else-codex-for-knowledge-work-claude-for-creative-work" aria-label="Permalink to &quot;[[AINews] Agents for Everything Else: Codex for Knowledge Work, Claude for Creative Work](https://www.latent.space/p/ainews-agents-for-everything-else)&quot;">​</a></h2><p><em>🔬 Latent Space | 2026-05-01</em></p><p>We mentioned on <a href="https://www.latent.space/p/unsupervised-learning-2026" target="_blank" rel="noreferrer">the Unsupervised Learning pod</a> about the thesis that “coding agents are breaking containment”, and that talk is <a href="https://www.youtube.com/watch?v=zepu8Kk6FBQ" target="_blank" rel="noreferrer">published live</a> today.</p><p>Some launches are discrete; others roll up over time. Both Claude and Codex had very big weeks, with Claude generally winning the impression count war as <a href="https://www.latent.space/p/ainews-the-biggest-claude-launch?utm_source=publication-search" target="_blank" rel="noreferrer">has been happening for a while now</a>.</p><p>Codex</p><p>Today’s big Codex update was “<a href="https://chatgpt.com/codex/for-work/" target="_blank" rel="noreferrer">Codex for Work</a>”, basically a landing page that pitches Codex for Knowledge Work (not just coding), following on from last week’s beginnings of turning Codex into the <a href="https://www.latent.space/p/ainews-gpt-55-and-openai-codex-superapp" target="_blank" rel="noreferrer">presumptive OpenAI “SuperApp</a>”. But it’s not just a landing page update; the latest Codex now has <a href="https://x.com/AriX/status/2049932746567598472?s=20" target="_blank" rel="noreferrer">42% faster CUA</a>, <a href="https://x.com/JamesZmSun/status/2050050523794165816" target="_blank" rel="noreferrer">responsive browser</a>, <a href="https://x.com/Dimillian/status/2049929842133520577?s=20" target="_blank" rel="noreferrer">/chronicle</a>, <a href="https://x.com/mweinbach/status/2049904712510521853" target="_blank" rel="noreferrer">/goal</a> (“<a href="https://x.com/fcoury/status/2049917871799636201?s=20" target="_blank" rel="noreferrer">our take on the Ralph loop</a>), and the onboarding now encourages you to plug into the <a href="https://x.com/OpenAI/status/2049928777480974606?s=20" target="_blank" rel="noreferrer">Microsoft/Google/Salesforce suite</a> and the agent now has a curiously Cowork-like <a href="https://x.com/OpenAI/status/2049928780588966270?s=20" target="_blank" rel="noreferrer">planning UI</a> and shows an <a href="https://x.com/OpenAI/status/2049928782019256561?s=20" target="_blank" rel="noreferrer">in-app file editor</a> for MS Office files.</p><p>Basically, as Tibo says, “<a href="https://x.com/thsottiaux/status/2049933460756979719?s=20" target="_blank" rel="noreferrer">Codex now available for non-coders</a>”, Greg “<a href="https://x.com/gdb/status/2049934863818494205" target="_blank" rel="noreferrer">Codex is for everyone, for any task done with a computer</a>”, and Sam “<a href="https://x.com/sama/status/2049946120441520624?s=20" target="_blank" rel="noreferrer">try it for non-coding computer work</a>.” You get the picture.</p><p>The “<a href="https://x.com/ajambrosino/status/2049928915872075984" target="_blank" rel="noreferrer">dynamic UI</a>” is an interesting choice - the team <a href="https://x.com/ajambrosino/status/2049942268812140825?s=20" target="_blank" rel="noreferrer">explicitly rejects</a> the Claude Cowork-like toggle, choosing instead to let the agent route the UI experience.</p><p><a href="https://x.com/ajambrosino/status/2049940619964076167?s=20" target="_blank" rel="noreferrer">source</a></p><p>Claude</p><p>Against the backdrop of <a href="https://x.com/kevinakwok/status/2049984076141281482" target="_blank" rel="noreferrer">increasing security vulnerabilities</a>, and a meta mythos around Mythos, Anthropic launched <a href="https://x.com/claudeai/status/2049898739783897537?s=20" target="_blank" rel="noreferrer">Claude Security</a>, a code review tool.</p><p>But probably the bigger news this week was the support of <a href="https://x.com/claudeai/status/2049143442601546054?s=20" target="_blank" rel="noreferrer">creative tools</a> like Blender, Autodesk, Adobe Creative Cloud, Ableton, Splice, Canva Affinity, and more.</p><p>AI News for 4/29/2026-4/30/2026. We checked 12 subreddits, <a href="https://twitter.com/i/lists/1585430245762441216" target="_blank" rel="noreferrer">544 Twitters</a> and no further Discords. <a href="https://news.smol.ai/" target="_blank" rel="noreferrer">AINews’ website</a> lets you search all past issues. As a reminder, <a href="https://www.latent.space/p/2026" target="_blank" rel="noreferrer">AINews is now a section of Latent Space</a>. You can <a href="https://support.substack.com/hc/en-us/articles/8914938285204-How-do-I-subscribe-to-or-unsubscribe-from-a-section-on-Substack" target="_blank" rel="noreferrer">opt in/out</a> of email frequencies!</p><p>AI Twitter Recap</p><p>OpenAI’s GPT-5.5, Codex expansion, and cyber capability evaluations</p><p>GPT-5.5 is now credibly in the top tier for long-horizon cyber tasks: the UK AI Security Institute reported that <a href="https://x.com/AISecurityInst/status/2049868227740565890" target="_blank" rel="noreferrer">GPT-5.5 became the second model to complete one of its multi-step cyber-attack simulations end-to-end</a>, and multiple follow-on posts highlighted rough parity with Claude Mythos Preview on this eval: <a href="https://x.com/scaling01/status/2049870801998864606" target="_blank" rel="noreferrer">@scaling01</a> cited 71.4% average pass rate for GPT-5.5 vs 68.6% for Mythos, while <a href="https://x.com/cryps1s/status/2049879762169167898" target="_blank" rel="noreferrer">@cryps1s</a> noted GPT-5.5 solved the TLO chain in 2/10 attempts vs Mythos’ 3/10. <a href="https://x.com/polynoamial/status/2049883449327243413" target="_blank" rel="noreferrer">@polynoamial</a> emphasized that performance was still improving past 100M tokens of inference budget, suggesting no obvious saturation yet. This materially changes the earlier narrative that Anthropic had a unique lead in offensive cyber automation. OpenAI also paired this moment with a product-side security release: <a href="https://x.com/OpenAI/status/2049902506881462613" target="_blank" rel="noreferrer">Advanced Account Security for ChatGPT</a>, adding phishing-resistant sign-in and hardened recovery.</p><p>Codex is moving beyond coding into general computer work: OpenAI shipped a substantial Codex update framed explicitly as “for everyone, for any task done with a computer,” with <a href="https://x.com/OpenAI/status/2049928776147230886" target="_blank" rel="noreferrer">the main announcement</a> highlighting role-based onboarding, app connections, and workflows spanning docs, slides, spreadsheets, research, and planning. <a href="https://x.com/ajambrosino/status/2049928915872075984" target="_blank" rel="noreferrer">@ajambrosino</a> summarized the update as dynamic task-specific UI, 20% faster computer/browser use, better slide/sheet handling, and less clunky handoffs, while <a href="https://x.com/AriX/status/2049932746567598472" target="_blank" rel="noreferrer">@AriX</a> called out that Computer Use runs 42% faster after the update. Sam Altman amplified the launch with <a href="https://x.com/sama/status/2049946120441520624" target="_blank" rel="noreferrer">“big upgrade for codex today! try it for non-coding computer work.”</a> The broader pattern: OpenAI is productizing “computer-use agent” UX, not just model capability.</p><p>Benchmark deltas were incremental but economically meaningful: <a href="https://x.com/ArtificialAnlys/status/2049926072595280030" target="_blank" rel="noreferrer">Artificial Analysis</a> reported GPT-5.5 Pro as a slight new SOTA on CritPt over GPT-5.4 Pro, but the interesting point was not raw score—it achieved the bump with ~60% lower cost and token use on that frontier-science eval. That lines up with broader chatter that the GPT-5.5 family is less about a dramatic intelligence discontinuity than about stronger reliability and better efficiency in high-value workflows.</p><p>Open-weight model movement: Qwen3.6, Tencent Hy3-preview, Grok 4.3, and Ling 2.6 1T</p><p>Qwen3.6 27B looks like the most important open-weight release of the day: <a href="https://x.com/ArtificialAnlys/status/2049881951260283097" target="_blank" rel="noreferrer">Artificial Analysis</a> ranked Qwen3.6 27B as the new open-weights leader under 150B parameters with an Intelligence Index score of 46, ahead of Gemma 4 31B and prior Qwen variants. Key details: Apache 2.0, 262K context, native multimodal input, and BF16 weights small enough to fit on a single H100. The companion 35B A3B MoE scored 43, making it the strongest open model around 3B active parameters. The tradeoff is expensive inference-by-output-token: AA estimates Qwen3.6 27B used ~144M output tokens on the suite and is roughly 21× the cost of Gemma 4 31B to run there. Still, on capability-per-size it appears to be a notable step.</p><p>Tencent’s Hy3-preview is competitive but not class-leading: <a href="https://x.com/ArtificialAnlys/status/2049852417316143393" target="_blank" rel="noreferrer">Artificial Analysis</a> described Hy3-preview as a 295B total / 21B active MoE with 256K context and a restricted-commercial-use community license. It scored 42 on AA’s Intelligence Index, trailing recent open peers like Qwen3.6 27B, DeepSeek V4 Flash, and GLM-5.1. The most interesting bright spot was CritPt, where it matched GLM-5.1 at 4.6%, suggesting better-than-average scientific reasoning relative to its overall position.</p><p>xAI’s Grok 4.3 improved sharply on agentic benchmarks while getting cheaper: <a href="https://x.com/ArtificialAnlys/status/2049987001655714250" target="_blank" rel="noreferrer">Artificial Analysis</a> measured Grok 4.3 at 53 on the Intelligence Index, up four points from Grok 4.20 v2, with a major jump on GDPval-AA to 1500 Elo. AA also reported approximately 40% lower input price and 60% lower output price than the prior version. The release still trails GPT-5.5 on GDPval-AA by a wide margin, but it looks like a real systems-and-post-training improvement rather than a minor rev.</p><p>Ant Group’s Ling 2.6 1T targets cost-efficiency rather than frontier status: <a href="https://x.com/ArtificialAnlys/status/2049923495602303438" target="_blank" rel="noreferrer">Artificial Analysis</a> positioned Ling 2.6 1T as a 1T-parameter non-reasoning model scoring 34, with decent GPQA/HLE numbers and notably low benchmark-run cost at roughly $95. The caveat is reliability: AA reported a 92% hallucination rate on AA-Omniscience.</p><p>DeepSeek multimodal/vision work, GUI agents, and training scale speculation</p><p>DeepSeek’s multimodal direction appears tightly coupled to computer-use agents: <a href="https://x.com/nrehiew_/status/2049840778491662623" target="_blank" rel="noreferrer">@nrehiew_</a> highlighted that DeepSeek trains vision into V4-Flash by having the model directly output bounding boxes and point coordinates during reasoning, interpreting this as a computer-use-oriented design rather than generic VLM work. A second post argues the paper’s “visual primitives” tasks map directly to browser/computer use rather than broad multimodal understanding (<a href="https://x.com/nrehiew_/status/2049840802562740311" target="_blank" rel="noreferrer">link</a>). That framing matches parallel observations from <a href="https://x.com/teortaxesTex/status/2049871869847765212" target="_blank" rel="noreferrer">@teortaxesTex</a> that DeepSeek may be integrating vision weights back into the main V4 line rather than releasing a separate “V4-Flash-Vision”.</p><p>The repo disappearance became a story of its own: after release, several observers noted that DeepSeek’s “Thinking with Visual Primitives” repo vanished, including <a href="https://x.com/teortaxesTex/status/2049880056420298995" target="_blank" rel="noreferrer">@teortaxesTex</a> and <a href="https://x.com/arjunkocher/status/2049875566678118898" target="_blank" rel="noreferrer">@arjunkocher</a>. No clear explanation emerged in these tweets, but the deletion drew more attention because the work suggested a concrete recipe for visual reasoning and GUI grounding.</p><p>Scaling chatter points to very large token counts for frontier pretraining: <a href="https://x.com/teortaxesTex/status/2049830477167526255" target="_blank" rel="noreferrer">@teortaxesTex</a> argued that &gt;100T tokens is no longer unusual for frontier models and estimated a hypothetical 100T-token DeepSeek V4 as “V4 + 2 more epochs,” while <a href="https://x.com/nrehiew_/status/2049848830292856970" target="_blank" rel="noreferrer">@nrehiew_</a> back-of-the-enveloped ~150T tokens and ~9e25 pretraining FLOPs for a ~100B active model, suggesting a run feasible in roughly 14 days on an OpenAI-scale 100K GB200 cluster at conservative MFU. These are speculative takes, but useful as calibration for what “frontier-scale” now means in practice.</p><p>Agent infrastructure, harness engineering, and collaborative agent systems</p><p>There is a clear shift from model-centric bragging to harness-centric engineering: Cursor published a strong note on <a href="https://x.com/cursor_ai/status/2049901436918436249" target="_blank" rel="noreferrer">how it tests and tunes its agent harness</a>, focusing on runtime, evals, degradation repair, and model-specific customization rather than generic benchmark claims. <a href="https://x.com/Vtrivedy10/status/2049919247321813491" target="_blank" rel="noreferrer">@Vtrivedy10</a> explicitly connected Cursor’s writeup to design patterns converging across agent builders: bespoke prompts/tools per model, mixed offline+online evals, dogfooding, and treating the context window as the primary compute boundary.</p><p>LangChain continues to package deployment and multi-tenant agent infra: <a href="https://x.com/hwchase17/status/2049858892637892739" target="_blank" rel="noreferrer">@hwchase17</a> introduced DeepAgents deploy, a config-driven cloud deployment flow via deepagents.toml, covering agent, sandbox, auth, and frontend sections. Related posts from LangChain staff detailed agent-server patterns for data isolation, delegated credentials, and RBAC in multi-user deployments (<a href="https://x.com/sydneyrunkle/status/2049956826670911809" target="_blank" rel="noreferrer">example</a>). This is increasingly the boring-but-important layer turning demos into enterprise software.</p><p>Collaborative multi-agent workspaces are getting more concrete: <a href="https://x.com/cmpatino_/status/2049881579691139372" target="_blank" rel="noreferrer">@cmpatino_</a> introduced Agent Collabs, using Hugging Face buckets plus Spaces as a shared backend for swarms of heterogeneous agents to exchange messages, artifacts, and progress. The noteworthy idea is not just “agents collaborating,” but lightweight coordination primitives that let weaker agents contribute useful validation work while better-resourced agents handle expensive experiments.</p><p>Security, supply chain, and account hardening</p><p>Open-source package compromise remains an acute operational risk: <a href="https://x.com/SocketSecurity/status/2049849100548424180" target="_blank" rel="noreferrer">Socket</a> reported that the popular PyPI package lightning was compromised in versions 2.6.2 and 2.6.3, with malicious code executing on import, downloading Bun, and running an 11 MB obfuscated JavaScript payload aimed at credential theft. <a href="https://x.com/theo/status/2049914688318959952" target="_blank" rel="noreferrer">@theo</a> connected that incident with additional package compromises (intercom-client on npm) and a Linux zero day, arguing the tempo of software supply-chain attacks is increasing.</p><p>Security scanners are becoming first-class AI products: Anthropic rolled out Claude Security, described by <a href="https://x.com/kimmonismus/status/2049901987500552195" target="_blank" rel="noreferrer">@kimmonismus</a> and later <a href="https://x.com/_catwu/status/2049964403177689130#m" target="_blank" rel="noreferrer">@_catwu</a> as a repo vulnerability scanner that validates findings and suggests fixes, powered by Opus 4.7. Cursor shipped a parallel offering with <a href="https://x.com/cursor_ai/status/2049926283061035254" target="_blank" rel="noreferrer">Cursor Security Review</a>, including always-on PR review and scheduled codebase scans. This is one of the clearest examples of model vendors moving directly into established devsecops categories.</p><p>Top tweets (by engagement)</p><p>OpenAI Codex broadens into general knowledge work: <a href="https://x.com/OpenAI/status/2049928776147230886" target="_blank" rel="noreferrer">OpenAI’s Codex announcement</a> and <a href="https://x.com/sama/status/2049946120441520624" target="_blank" rel="noreferrer">Sam Altman’s follow-up</a> were the day’s biggest product posts, signaling a strategic push from “coding agent” to “computer-use agent”.</p><p>GPT-5.5’s cyber eval result mattered: <a href="https://x.com/AISecurityInst/status/2049868227740565890" target="_blank" rel="noreferrer">UK AISI’s thread</a> was one of the highest-engagement technical posts and reshaped comparisons with Anthropic’s Mythos.</p><p>Qwen shipped interpretability tooling, not just models: <a href="https://x.com/Alibaba_Qwen/status/2049861145574690992" target="_blank" rel="noreferrer">Qwen-Scope</a>, an open suite of sparse autoencoders for Qwen models, stood out as a rare release focused on feature steering, debugging, data synthesis, and evaluation rather than raw model weights.</p><p>Anthropic published a large-scale guidance/sycophancy study: <a href="https://x.com/AnthropicAI/status/2049927618397614466" target="_blank" rel="noreferrer">their analysis of 1M Claude conversations</a> tied behavioral research directly to training changes for Opus 4.7 and Mythos Preview, an important sign that post-training loops are becoming more productized and data-informed.</p><p>AI Reddit Recap</p><p>/r/LocalLlama + /r/localLLM Recap</p><ol><li>AMD Ryzen 395 Box and Halo Box Launch</li></ol><p><a href="https://www.latent.space/p/ainews-agents-for-everything-else" target="_blank" rel="noreferrer"> Read more </a></p><hr>',47)])])}const g=t(s,[["render",o]]);export{u as __pageData,g as default};
